import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';

export default defineConfig({
  plugins: [react()],
  envPrefix: ['VITE_', 'NEXT_PUBLIC_'], // Allow Vercel's auto-generated env vars
});

import { createClient } from '@supabase/supabase-js';

// Support both Vercel's auto-gen names (NEXT_PUBLIC_) and manual Vite names (VITE_)
const supabaseUrl = import.meta.env.NEXT_PUBLIC_SUPABASE_URL || import.meta.env.VITE_SUPABASE_URL;
const supabaseAnonKey = import.meta.env.NEXT_PUBLIC_SUPABASE_ANON_KEY || import.meta.env.VITE_SUPABASE_ANON_KEY;

if (!supabaseUrl || !supabaseAnonKey) {
  console.error("Missing Supabase Environment Variables. Check Vercel Settings.");
}

export const supabase = createClient(supabaseUrl || '', supabaseAnonKey || '');

import { supabase } from './supabase';

/**
 * Saves data to LocalStorage (for instant UI update) AND Supabase (for cloud persistence).
 */
export const saveData = async (key: string, data: any) => {
  // 1. Local Save (Synchronous, instant)
  const stringValue = JSON.stringify(data);
  localStorage.setItem(key, stringValue);

  // 2. Cloud Save (Asynchronous, fire-and-forget)
  const { data: { session } } = await supabase.auth.getSession();

  if (session?.user) {
    try {
      const { error } = await supabase
        .from('user_storage')
        .upsert(
          { 
            user_id: session.user.id, 
            key: key, 
            value: data 
          }, 
          { onConflict: 'user_id, key' }
        );

      if (error) console.error("Cloud Save Error:", error);
    } catch (err) {
      console.error("Supabase Connection Error", err);
    }
  }
};

/**
 * Helper to get data from LocalStorage (Read operations are always local for speed)
 */
export const loadData = <T>(key: string): T | null => {
  const saved = localStorage.getItem(key);
  if (saved) {
    try {
      return JSON.parse(saved) as T;
    } catch (e) {
      console.error("Parse Error", e);
      return null;
    }
  }
  return null;
};

/**
 * Deletes data from both Local and Cloud
 */
export const removeData = async (key: string) => {
  localStorage.removeItem(key);

  const { data: { session } } = await supabase.auth.getSession();
  if (session?.user) {
    await supabase.from('user_storage').delete().match({ user_id: session.user.id, key: key });
  }
};

