                        </div>
                    </div>
                    <div className="flex-1 bg-gray-100 dark:bg-gray-900 p-0 md:p-4 overflow-hidden relative">
                        <object data={pdfPreviewUrl} type="application/pdf" className="w-full h-full rounded-xl">
