                                <Button onClick={handleDownloadPdf}>Download PDF</Button>
                            </div>
                        </object>
                    </div>
                </div>
            </div>
        )}

        <div className="flex flex-col md:flex-row justify-between items-center gap-4 mb-2">
            <div className="flex flex-wrap gap-2 p-1 bg-gray-100 dark:bg-indigo-950/50 rounded-xl w-full md:w-fit justify-center md:justify-start">
                <button onClick={() => setActiveTab('weight')} className={`flex-1 md:flex-none px-4 md:px-6 py-2 rounded-lg text-sm font-bold transition-all flex justify-center items-center gap-2 ${activeTab === 'weight' ? 'bg-white dark:bg-deep-card shadow text-pink-600' : 'text-gray-500 hover:text-gray-700 dark:hover:text-gray-300'}`}>
                    {isPostpartum ? <Baby size={18} /> : <Scale size={18} />} <span className="whitespace-nowrap">{isPostpartum ? "Baby Growth" : "Weight"}</span>
                </button>
                <button onClick={() => setActiveTab('vitals')} className={`flex-1 md:flex-none px-4 md:px-6 py-2 rounded-lg text-sm font-bold transition-all flex justify-center items-center gap-2 ${activeTab === 'vitals' ? 'bg-white dark:bg-deep-card shadow text-blue-600' : 'text-gray-500 hover:text-gray-700 dark:hover:text-gray-300'}`}>
