                                <Button onClick={addBP} className="flex-1"><Plus size={18} /></Button>
                            </div>
                            <div className="space-y-2 max-h-60 overflow-y-auto pr-1 custom-scrollbar">
                                {bpLogs.map(log => (
                                    <div key={log.id} className="p-3 bg-gray-50 dark:bg-indigo-900/10 rounded-xl border"><span className="font-bold text-lg">{log.systolic}/{log.diastolic}</span></div>
