  const DATE_KEY = STORAGE_KEY + '_date';

  useEffect(() => {
    const loadMedicines = () => {
        const saved = localStorage.getItem(STORAGE_KEY);
        const lastDate = localStorage.getItem(DATE_KEY);
        const today = new Date().toISOString().split('T')[0];

        if (saved) {
            let parsed = JSON.parse(saved);
            if (lastDate !== today) {
                parsed = parsed.map((m: Medicine) => ({ ...m, taken: false }));
                saveData(STORAGE_KEY, parsed);
                localStorage.setItem(DATE_KEY, today);
            }
            setMedicines(parsed);
        } else {
            const defaults: Medicine[] = isPostpartum ? [
                { id: '1', name: 'Calcium', dosage: '500mg', frequency: 'BD', time: '09:00', taken: false },
                { id: '2', name: 'Iron', dosage: '100mg', frequency: 'OD', time: '20:00', taken: false }
            ] : [
                { id: '1', name: 'Folic Acid', dosage: '5mg', frequency: 'Daily', time: '09:00', taken: false },
                { id: '2', name: 'Iron Supplement', dosage: '100mg', frequency: 'Daily', time: '20:00', taken: false }
            ];
            setMedicines(defaults);
            saveData(STORAGE_KEY, defaults);
            localStorage.setItem(DATE_KEY, today);
        }
    };
    loadMedicines();
  }, [isPostpartum]);

  const toggleTaken = (id: string) => {
    const updated = medicines.map(m => m.id === id ? { ...m, taken: !m.taken } : m);
    setMedicines(updated);
    saveData(STORAGE_KEY, updated);
  };

  const addMed = () => {
    if (newMed.name && newMed.time) {
      const updated = [...medicines, {
        id: Date.now().toString(),
        name: newMed.name,
        time: newMed.time,
        dosage: 'Check label',
        frequency: 'Daily',
        taken: false
      }];
      setMedicines(updated);
      saveData(STORAGE_KEY, updated);
      setNewMed({ name: '', time: '' });
    }
  };

  const removeMed = (id: string) => {
    const updated = medicines.filter(m => m.id !== id);
    setMedicines(updated);
    saveData(STORAGE_KEY, updated);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-fade-in pb-10">
       <div className="flex gap-2 p-1 bg-gray-100 dark:bg-indigo-950/50 rounded-xl w-fit mx-auto mb-6">
          <button 
             onClick={() => setActiveTab('my-meds')}
             className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'my-meds' ? 'bg-white dark:bg-deep-card shadow text-teal-600 dark:text-teal-400' : 'text-gray-500 hover:text-gray-700 dark:hover:text-gray-300'}`}
          >
             My Medicines
          </button>
          <button 
             onClick={() => setActiveTab('safety')}
             className={`px-6 py-2 rounded-lg text-sm font-bold transition-all flex items-center gap-2 ${activeTab === 'safety' ? 'bg-white dark:bg-deep-card shadow text-bloom-DEFAULT' : 'text-gray-500 hover:text-gray-700 dark:hover:text-gray-300'}`}
          >
             <ShieldAlert size={16} /> {isPostpartum ? 'Lactation Safety' : 'Safety Guide'}
          </button>
       </div>

       {activeTab === 'my-meds' ? (
         <>
          <div className="bg-gradient-to-r from-teal-500 to-emerald-500 rounded-3xl p-8 text-white shadow-lg">
              <h2 className="text-2xl font-bold mb-2">Medicine Cabinet</h2>
              <p className="opacity-90">Keep track of your supplements and prescriptions. Compliance is key for a healthy {isPostpartum ? 'recovery' : 'pregnancy'}.</p>
          </div>

          <div className="bg-white dark:bg-deep-card rounded-3xl shadow-lg border border-gray-100 dark:border-indigo-800 overflow-hidden">
              <div className="p-6 border-b border-gray-100 dark:border-indigo-800">
                <h3 className="font-bold text-gray-800 dark:text-white text-lg">Daily Checklist</h3>
              </div>

              <div className="divide-y divide-gray-100 dark:divide-indigo-800">
                {medicines.map(med => (
                  <div key={med.id} className={`p-4 flex items-center justify-between transition-colors ${med.taken ? 'bg-green-50/50 dark:bg-green-900/10' : 'hover:bg-gray-50 dark:hover:bg-indigo-900/20'}`}>
                      <div className="flex items-center gap-4">
                        <button onClick={() => toggleTaken(med.id)} className={`w-8 h-8 rounded-full border-2 flex items-center justify-center transition-all ${med.taken ? 'bg-green-500 border-green-500 text-white' : 'border-gray-300 dark:border-gray-600 text-transparent hover:border-green-500'}`}>
                            <Check size={16} />
                        </button>
                        <div>
                            <p className={`font-medium text-lg ${med.taken ? 'text-gray-400 line-through' : 'text-gray-800 dark:text-white'}`}>{med.name}</p>
                            <p className="text-sm text-gray-500 dark:text-gray-400">{med.time} • {med.dosage}</p>
                        </div>
                      </div>
                      <button onClick={() => removeMed(med.id)} className="text-gray-400 hover:text-red-500 p-2"><Trash2 size={18} /></button>
                  </div>
                ))}
              </div>

              <div className="p-6 bg-gray-50 dark:bg-indigo-950/30">
                <div className="flex flex-col md:flex-row gap-4 items-end">
                    <div className="flex-1 w-full">
                        <label className="block text-xs font-bold text-gray-500 dark:text-gray-400 uppercase mb-1">Medicine Name</label>
                        <input type="text" value={newMed.name} onChange={(e) => setNewMed({...newMed, name: e.target.value})} className="w-full px-4 py-2 rounded-xl border" placeholder="e.g. Calcium" />
                    </div>
                    <div className="w-full md:w-40">
                        <label className="block text-xs font-bold text-gray-500 dark:text-gray-400 uppercase mb-1">Time</label>
                        <input type="time" value={newMed.time} onChange={(e) => setNewMed({...newMed, time: e.target.value})} className="w-full px-4 py-2 rounded-xl border" />
                    </div>
                    <Button onClick={addMed} className="w-full md:w-auto bg-teal-500 hover:bg-teal-600"><Plus size={20} /> Add</Button>
                </div>
              </div>
          </div>
         </>
       ) : (
         <MedicineSafety currentWeek={currentWeek} isPostpartum={isPostpartum} mode={mode} comorbidities={comorbidities} />
       )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Button } from './Button';
import { Contraction } from '../types';
import { Play, Square, RotateCcw, AlertCircle, Clock, Activity } from 'lucide-react';
import { saveData, removeData } from '../services/storage';

export const ContractionTimer: React.FC = () => {
  const [contractions, setContractions] = useState<Contraction[]>([]);
  const [activeId, setActiveId] = useState<string | null>(null);
  const [timer, setTimer] = useState(0);

  useEffect(() => {
    const saved = localStorage.getItem('bloom_contractions');
    if (saved) {
      setContractions(JSON.parse(saved));
    }
  }, []);

  useEffect(() => {
    let interval: number;
    if (activeId) {
      interval = window.setInterval(() => {
        setTimer(prev => prev + 1);
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [activeId]);

  const toggleTimer = () => {
    if (activeId) {
      const updated = contractions.map(c => {
        if (c.id === activeId) {
          return {
            ...c,
            endTime: new Date().toISOString(),
            durationSeconds: timer
          };
        }
        return c;
      });
      setContractions(updated);
      saveData('bloom_contractions', updated);
      setActiveId(null);
      setTimer(0);
    } else {
      const now = new Date();
      const lastContraction = contractions.length > 0 ? contractions[0] : null;
      let frequency = null;
      if (lastContraction) {
        const lastStart = new Date(lastContraction.startTime).getTime();
        const currentStart = now.getTime();
        frequency = Math.floor((currentStart - lastStart) / 1000);
      }
      const newContraction: Contraction = {
        id: Date.now().toString(),
        startTime: now.toISOString(),
        endTime: null,
        durationSeconds: 0,
        frequencySeconds: frequency
      };
      const updated = [newContraction, ...contractions];
      setContractions(updated);
      saveData('bloom_contractions', updated);
      setActiveId(newContraction.id);
      setTimer(0);
    }
  };

  const resetAll = () => {
    if (confirm("Delete all contraction history?")) {
      setContractions([]);
      removeData('bloom_contractions');
      setActiveId(null);
      setTimer(0);
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs < 10 ? '0' : ''}${secs}`;
  };

  const formatDuration = (seconds: number) => {
     if (seconds < 60) return `${seconds}s`;
     return `${Math.floor(seconds/60)}m ${seconds%60}s`;
  };

  const formatFreq = (seconds: number | null) => {
     if (!seconds) return '-';
     const mins = Math.floor(seconds / 60);
     return `${mins} min`;
  };

  const analyzeLabor = () => {
      if (contractions.length < 3) return null;
      const recent = contractions.slice(0, 5); 
      const avgFreq = recent.reduce((acc, c) => acc + (c.frequencySeconds || 0), 0) / (recent.length - 1);
      const avgDur = recent.reduce((acc, c) => acc + c.durationSeconds, 0) / recent.length;

      if (avgFreq > 0 && avgFreq <= 360 && avgDur >= 45) {
          return { status: 'hospital', message: "Hospital Alert! Contractions are consistent (~5 min apart). Call your doctor." };
      }
      if (avgFreq > 0 && avgFreq <= 600) {
          return { status: 'prepare', message: "Labor may be progressing. Pack your bags." };
      }
      return { status: 'early', message: "Early labor or Braxton Hicks. Keep monitoring." };
  };

  const alert = analyzeLabor();

  return (
    <div className="space-y-6 animate-fade-in">
      <div className={`rounded-3xl p-8 text-white shadow-xl transition-colors duration-500 relative overflow-hidden ${activeId ? 'bg-green-600' : 'bg-gradient-to-br from-blue-600 to-indigo-600'}`}>
         {activeId && <div className="absolute inset-0 bg-green-500 animate-pulse opacity-50"></div>}
         <div className="relative z-10 flex flex-col items-center justify-center text-center">
             <h2 className="text-xl font-bold uppercase tracking-widest opacity-80 mb-2">{activeId ? "Contraction Active" : "Ready to Timer"}</h2>
             <div className="text-7xl font-mono font-bold mb-8 tabular-nums">{formatTime(timer)}</div>
             <button onClick={toggleTimer} className={`w-24 h-24 rounded-full flex items-center justify-center shadow-lg transition-transform active:scale-90 ${activeId ? 'bg-white text-green-600 hover:bg-gray-100' : 'bg-white text-indigo-600 hover:bg-gray-100'}`}>
                {activeId ? <Square size={32} fill="currentColor" /> : <Play size={36} fill="currentColor" className="ml-1" />}
             </button>
             <p className="mt-6 font-medium opacity-90">{activeId ? "Breathe... Relax your shoulders." : "Press Play when pain starts"}</p>
         </div>
      </div>

      {alert && contractions.length >= 3 && (
          <div className={`p-4 rounded-xl border flex gap-3 items-start ${alert.status === 'hospital' ? 'bg-red-100 border-red-300 text-red-800' : alert.status === 'prepare' ? 'bg-orange-100 border-orange-300 text-orange-800' : 'bg-blue-50 border-blue-200 text-blue-800'}`}>
              <AlertCircle className="shrink-0 mt-0.5" />
              <div><h4 className="font-bold">Analysis</h4><p className="text-sm">{alert.message}</p></div>
          </div>
      )}

      <div className="bg-white dark:bg-deep-card rounded-3xl shadow-lg border border-gray-100 dark:border-indigo-800 overflow-hidden">
          <div className="p-4 border-b border-gray-100 dark:border-indigo-800 flex justify-between items-center">
              <h3 className="font-bold text-gray-800 dark:text-white flex items-center gap-2"><Activity size={20} /> History</h3>
              {contractions.length > 0 && <button onClick={resetAll} className="text-xs text-red-500">Reset</button>}
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left text-sm">
                <thead className="bg-gray-50 dark:bg-indigo-900/30 text-gray-500 dark:text-gray-400">
                    <tr><th className="p-4 font-bold">Start Time</th><th className="p-4 font-bold">Duration</th><th className="p-4 font-bold">Frequency</th></tr>
                </thead>
                <tbody className="divide-y divide-gray-100 dark:divide-indigo-800">
                    {contractions.length === 0 ? (<tr><td colSpan={3} className="p-8 text-center text-gray-400">No contractions recorded.</td></tr>) : (
                        contractions.map((c, i) => (
                            <tr key={c.id} className={i === 0 && activeId ? "bg-green-50 dark:bg-green-900/10 animate-pulse" : ""}>
                                <td className="p-4 text-gray-800 dark:text-white">{new Date(c.startTime).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</td>
                                <td className="p-4 font-bold text-gray-800 dark:text-white">{c.endTime || activeId === c.id ? formatDuration(c.durationSeconds) : '...'}</td>
                                <td className="p-4 text-gray-600 dark:text-gray-300">{formatFreq(c.frequencySeconds)}</td>
                            </tr>
                        ))
                    )}
                </tbody>
            </table>
          </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { UserSettings, DietType, AppMode, ProfileMeta } from '../types';
import { Button } from './Button';
import { RefreshCw, User, Calendar, Activity, Utensils, Baby, Ruler, Weight, ArrowRightLeft, HeartPulse, Droplet, AlertTriangle, CheckCircle2, FlaskConical, Stethoscope, Info, X, Users, Plus, ChevronRight, FileText, Clock, Sparkles, Key, ExternalLink, Eye, EyeOff } from 'lucide-react';
import { COMORBIDITY_GUIDELINES, BLOOD_GROUPS } from '../constants';
import { saveData, removeData } from '../services/storage';

interface Props {
  settings: UserSettings;
  profiles?: ProfileMeta[];
  onUpdate: (settings: UserSettings) => void;
  onReset: () => void;
  onAddProfile?: () => void;
  onSwitchProfile?: (id: string) => void;
}

export const Profile: React.FC<Props> = ({ settings, profiles = [], onUpdate, onReset, onAddProfile, onSwitchProfile }) => {
  const [formData, setFormData] = useState<UserSettings>(settings);
  const [saved, setSaved] = useState(false);
  const [showBabyModal, setShowBabyModal] = useState(false);
  const [showResetConfirm, setShowResetConfirm] = useState(false);
  const [apiKey, setApiKey] = useState('');
  const [showApiKey, setShowApiKey] = useState(false);
  const [keySaved, setKeySaved] = useState(false);
  const [babyForm, setBabyForm] = useState<{name: string, date: string, gender: 'boy' | 'girl'}>({ name: '', date: '', gender: 'boy' });

  useEffect(() => {
    setFormData({
      ...settings,
      comorbidities: settings.comorbidities || [],
      dietaryPreference: settings.dietaryPreference || 'vegetarian',
      lactoseIntolerant: settings.lactoseIntolerant || false,
      vaccinationsDone: settings.vaccinationsDone || [],
      maternalBloodGroup: settings.maternalBloodGroup || '',
      paternalBloodGroup: settings.paternalBloodGroup || '',
      age: settings.age || undefined,
      paternalHeightCm: settings.paternalHeightCm || undefined,
      status: settings.status || (settings.isPostpartum ? 'postpartum' : 'pregnant'),
      periodLog: settings.periodLog || [],
      pregnancyLmp: settings.pregnancyLmp || null,
      obstetricHistory: settings.obstetricHistory || { gravida: 1, para: 0, abort: 0, living: 0 }
    });
    const storedKey = localStorage.getItem('bloom_user_api_key');
    if (storedKey) setApiKey(storedKey);
  }, [settings]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    let updatedSettings = { ...formData };

    if (formData.status === 'pregnant') {
        updatedSettings.pregnancyLmp = formData.lmp;
    } else if (formData.status === 'planning') {
        if (formData.lmp && !updatedSettings.periodLog.includes(formData.lmp)) {
            updatedSettings.periodLog = [...updatedSettings.periodLog, formData.lmp].sort().reverse();
        }
    }

    onUpdate(updatedSettings);

    if (apiKey) {
        saveData('bloom_user_api_key', apiKey); // Sync API Key too? Safe enough for this context as it's user provided
    } else {
        removeData('bloom_user_api_key');
    }

    setSaved(true);
    setKeySaved(true);
    setTimeout(() => {
        setSaved(false);
        setKeySaved(false);
    }, 2000);
  };

  const toggleComorbidity = (id: string) => {
    const current = formData.comorbidities || [];
    if (current.includes(id)) {
      setFormData({ ...formData, comorbidities: current.filter(c => c !== id) });
    } else {
      setFormData({ ...formData, comorbidities: [...current, id] });
    }
  };

  const enablePostpartumMode = () => {
    if(babyForm.name && babyForm.date) {
        onUpdate({
            ...formData,
            status: 'postpartum',
            isPostpartum: true,
            babyName: babyForm.name,
            babyGender: babyForm.gender,
            birthDate: babyForm.date
        });
        setShowBabyModal(false);
    }
  };

  const handleModeChange = (newMode: AppMode) => {
      if (newMode === 'postpartum') {
          setShowBabyModal(true);
          return;
      }
      let newLmp = formData.lmp;
      if (newMode === 'pregnant') {
          if (formData.pregnancyLmp) {
              newLmp = formData.pregnancyLmp;
          } else if (formData.periodLog && formData.periodLog.length > 0) {
              const sorted = [...formData.periodLog].sort((a, b) => new Date(b).getTime() - new Date(a).getTime());
              newLmp = sorted[0];
          }
      } else if (newMode === 'planning') {
          if (formData.periodLog && formData.periodLog.length > 0) {
              const sorted = [...formData.periodLog].sort((a, b) => new Date(b).getTime() - new Date(a).getTime());
              newLmp = sorted[0];
          }
      }
      onUpdate({ ...formData, status: newMode, isPostpartum: false, lmp: newLmp });
  };

  // ... [Calculations for Blood Group and Height Prediction omitted for brevity, logic remains identical] ... 
  const predictHeight = () => {
      if (formData.heightCm && formData.paternalHeightCm) {
          const m = formData.heightCm;
          const f = formData.paternalHeightCm;
          const boyTarget = (m + f + 13) / 2;
          const girlTarget = (m + f - 13) / 2;
          return { boy: boyTarget.toFixed(1), girl: girlTarget.toFixed(1) };
      }
      return null;
  };
  const predictedHeight = predictHeight();

  const getThemeColor = () => {
      if (settings.status === 'planning') return 'from-teal-500 to-emerald-600';
      if (settings.status === 'postpartum') {
          return settings.babyGender === 'boy' ? 'from-blue-600 to-cyan-600' : 'from-rose-400 to-pink-500';
      }
      return 'from-pink-600 to-purple-600'; 
  };

  const calculateAge = (birthDateString: string) => {
      const birth = new Date(birthDateString);
      const now = new Date();
      const diffTime = Math.abs(now.getTime() - birth.getTime());
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
      if (diffDays < 30) return `${diffDays} days old`;
      const months = Math.floor(diffDays / 30.4);
      if (months < 12) return `${months} months old`;
      const years = Math.floor(months / 12);
      const remMonths = months % 12;
      return `${years}y ${remMonths}m old`;
  };

  const updateObstetric = (field: string, value: any) => {
      setFormData({
          ...formData,
          obstetricHistory: { ...formData.obstetricHistory, [field]: value }
      });
  };

  return (
    <div className="max-w-2xl mx-auto space-y-8 animate-fade-in pb-10">

      <div className={`rounded-3xl p-6 text-white shadow-lg bg-gradient-to-r ${getThemeColor()}`}>
          <div className="flex flex-col md:flex-row gap-6 items-start md:items-center justify-between">
              <div>
                  <h3 className="text-lg font-bold flex items-center gap-2 opacity-90 text-sm uppercase tracking-wider mb-2">Current Stage</h3>
                  <p className="text-2xl font-bold leading-tight">{settings.status === 'planning' ? 'Planning Pregnancy' : settings.status === 'postpartum' ? 'Postpartum' : 'Pregnant'}</p>
              </div>
              <div className="flex flex-wrap gap-2 w-full md:w-auto">
                  <button onClick={() => handleModeChange('planning')} className={`flex-1 md:flex-none px-4 py-2 rounded-full text-sm font-bold transition-all border whitespace-nowrap ${settings.status === 'planning' ? 'bg-white text-teal-700 border-white shadow-md' : 'bg-black/10 text-white border-white/20 hover:bg-white/10'}`}>Planning</button>
                  <button onClick={() => handleModeChange('pregnant')} className={`flex-1 md:flex-none px-4 py-2 rounded-full text-sm font-bold transition-all border whitespace-nowrap ${settings.status === 'pregnant' ? 'bg-white text-pink-700 border-white shadow-md' : 'bg-black/10 text-white border-white/20 hover:bg-white/10'}`}>Pregnant</button>
                  <button onClick={() => handleModeChange('postpartum')} className={`flex-1 md:flex-none px-4 py-2 rounded-full text-sm font-bold transition-all border whitespace-nowrap ${settings.status === 'postpartum' ? 'bg-white text-blue-700 border-white shadow-md' : 'bg-black/10 text-white border-white/20 hover:bg-white/10'}`}>Baby Born</button>
              </div>
          </div>
      </div>

      <div className="bg-white dark:bg-deep-card p-6 rounded-3xl shadow-lg border border-gray-100 dark:border-indigo-800">
          <div className="flex items-center justify-between mb-4 border-b border-gray-100 dark:border-indigo-800 pb-4">
              <h3 className="text-xl font-bold text-gray-800 dark:text-white flex items-center gap-2"><Users size={20} className="text-indigo-600 dark:text-indigo-400" /> My Family Hub</h3>
              {onAddProfile && <Button onClick={onAddProfile} variant="secondary" className="text-xs"><Plus size={16} /> Add Baby</Button>}
