                  if (p.status === 'planning') { statusColor = 'bg-teal-500'; icon = <Calendar size={18} />; } 
                  else if (p.status === 'postpartum') { statusColor = p.babyGender === 'boy' ? 'bg-blue-500' : 'bg-pink-500'; } 
                  else { statusColor = 'bg-purple-500'; }

                  return (
                      <div key={p.id} className={`flex items-center justify-between p-4 rounded-2xl border transition-all ${isActive ? 'bg-indigo-50 dark:bg-indigo-900/30 border-indigo-200 dark:border-indigo-700 shadow-sm' : 'bg-gray-50 dark:bg-gray-800/50 border-gray-100 dark:border-indigo-900/30 hover:bg-gray-100 dark:hover:bg-indigo-900/20'}`}>
                          <div className="flex items-center gap-4">
                              <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-white shadow-sm ${statusColor}`}>{p.babyName ? p.babyName[0].toUpperCase() : icon}</div>
                              <div>
                                  <p className="font-bold text-gray-900 dark:text-white flex items-center gap-2">{p.babyName || (p.status === 'planning' ? 'Future Baby' : 'Baby Profile')} {p.status === 'postpartum' && <span className={`text-[10px] px-1.5 py-0.5 rounded-full font-bold uppercase ${p.babyGender === 'boy' ? 'bg-blue-100 text-blue-700' : 'bg-pink-100 text-pink-700'}`}>{p.babyGender}</span>}</p>
                                  <div className="flex gap-2 text-xs text-gray-500 dark:text-gray-400 items-center"><span className="capitalize">{p.status}</span>{p.birthDate && <><span className="w-1 h-1 bg-gray-300 rounded-full"></span><span className="flex items-center gap-1"><Clock size={10} /> {calculateAge(p.birthDate)}</span></>}{isActive && <span className="ml-1 px-1.5 py-0.5 bg-green-100 text-green-700 rounded text-[10px] font-bold">ACTIVE</span>}</div>
                              </div>
