                          {!isActive && onSwitchProfile && <button onClick={() => onSwitchProfile(p.id)} className="text-sm font-medium text-indigo-600 dark:text-indigo-400 flex items-center gap-1 hover:underline">Switch <ChevronRight size={16} /></button>}
                      </div>
