      <div className="bg-white dark:bg-deep-card p-8 rounded-3xl shadow-lg border border-gray-100 dark:border-indigo-800">
        <form onSubmit={handleSubmit} className="space-y-8">
          <div className="space-y-6">
             <h3 className="font-bold text-gray-800 dark:text-white flex items-center gap-2 border-b border-gray-100 dark:border-indigo-800 pb-3 mb-4"><Sparkles size={20} className="text-purple-500" /> AI Configuration</h3>
             <div className="bg-purple-50 dark:bg-purple-900/10 p-5 rounded-2xl border border-purple-100 dark:border-purple-900/30">
                 <div className="flex items-start gap-3 mb-4">
                     <div className="p-2 bg-purple-100 dark:bg-purple-800/50 rounded-full text-purple-600 dark:text-purple-300 shrink-0"><Key size={20} /></div>
                     <div>
                         <h4 className="font-bold text-gray-900 dark:text-white text-sm">Google Gemini API Key</h4>
                         <p className="text-xs text-gray-600 dark:text-gray-300 mt-1 leading-relaxed">Bloom uses advanced AI for medical analysis. To use these features, you need your own free Gemini API Key from Google.</p>
                         <a href="https://aistudio.google.com/app/apikey" target="_blank" rel="noopener noreferrer" className="inline-flex items-center gap-1 mt-2 text-xs font-bold text-purple-600 hover:text-purple-700 dark:text-purple-400 dark:hover:text-purple-300 hover:underline">Get your free key here <ExternalLink size={12} /></a>
                     </div>
                 </div>
                 <div className="relative">
                     <input type={showApiKey ? "text" : "password"} placeholder="Paste your API Key here (starts with AIza...)" value={apiKey} onChange={(e) => setApiKey(e.target.value)} className="w-full px-4 py-3 pr-12 rounded-xl border border-gray-200 dark:border-indigo-700 bg-white dark:bg-indigo-950/50 text-gray-900 dark:text-white outline-none focus:ring-2 focus:ring-purple-500 font-mono text-sm" />
                     <button type="button" onClick={() => setShowApiKey(!showApiKey)} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600 dark:hover:text-gray-200">{showApiKey ? <EyeOff size={18} /> : <Eye size={18} />}</button>
                 </div>
                 {keySaved && <p className="text-xs text-green-600 font-bold mt-2 flex items-center gap-1"><CheckCircle2 size={12}/> Key Saved Securely</p>}
             </div>
          </div>

          <div className="space-y-6">
            <h3 className="font-bold text-gray-800 dark:text-white flex items-center gap-2 border-b border-gray-100 dark:border-indigo-800 pb-3 mb-4"><User size={20} className="text-pink-500" /> Personal Details</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div><label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">Your Name</label><input type="text" required className="w-full px-4 py-3 rounded-xl border" value={formData.name} onChange={(e) => setFormData({...formData, name: e.target.value})} /></div>
                <div><label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">Maternal Age</label><input type="number" required className="w-full px-4 py-3 rounded-xl border" value={formData.age || ''} onChange={(e) => setFormData({...formData, age: parseInt(e.target.value)})} placeholder="e.g. 28" /></div>
            </div>

            <h3 className="font-bold text-gray-800 dark:text-white flex items-center gap-2 border-b border-gray-100 dark:border-indigo-800 pb-3 pt-4 mb-4"><FileText size={20} className="text-teal-500" /> Obstetric History</h3>
            <div className="p-5 bg-teal-50 dark:bg-teal-900/10 rounded-2xl space-y-5 border border-teal-100 dark:border-teal-900/30">
                <div className="grid grid-cols-2 gap-6">
                    <div><label className="block text-xs font-bold uppercase mb-1">Gravida</label><input type="number" min="1" className="w-full px-4 py-2 rounded-xl border" value={formData.obstetricHistory.gravida} onChange={(e) => updateObstetric('gravida', parseInt(e.target.value))} /></div>
                    <div><label className="block text-xs font-bold uppercase mb-1">Para</label><input type="number" min="0" className="w-full px-4 py-2 rounded-xl border" value={formData.obstetricHistory.para} onChange={(e) => updateObstetric('para', parseInt(e.target.value))} /></div>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div><label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">Current Weight (kg)</label><input type="number" className="w-full px-4 py-3 rounded-xl border" value={formData.prePregnancyWeight || ''} onChange={(e) => setFormData({...formData, prePregnancyWeight: parseInt(e.target.value)})} /></div>
                <div><label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">{formData.status === 'pregnant' ? 'Pregnancy Start (LMP)' : 'Last Period Start'}</label><input type="date" required className="w-full px-4 py-3 rounded-xl border" value={formData.lmp || ''} max={new Date().toISOString().split('T')[0]} onChange={(e) => setFormData({...formData, lmp: e.target.value})} /></div>
            </div>
          </div>

          <div className="pt-4 flex items-center gap-4">
            <Button type="submit" className="flex-1 py-3 !text-white bg-pink-600 hover:bg-pink-700" disabled={saved}>{saved ? 'Saved Successfully!' : 'Update Profile & Save Key'}</Button>
          </div>
        </form>
      </div>

      {showResetConfirm && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-md animate-fade-in">
              <div className="bg-white dark:bg-deep-card p-6 rounded-3xl shadow-2xl max-w-sm w-full border border-red-200 dark:border-red-900 transform transition-all scale-100">
                  <div className="flex justify-between items-start mb-4"><div className="p-3 bg-red-100 dark:bg-red-900/30 rounded-full text-red-600 dark:text-red-400"><AlertTriangle size={32} /></div><button onClick={() => setShowResetConfirm(false)} className="text-gray-400 hover:text-gray-600 dark:hover:text-white"><X size={24} /></button></div>
                  <h3 className="text-xl font-bold text-gray-900 dark:text-white mb-2">Reset App Data?</h3>
                  <p className="text-gray-600 dark:text-gray-300 text-sm mb-6 leading-relaxed">Are you sure you want to delete <strong>everything</strong>? <span className="font-bold text-red-500">This action cannot be undone.</span></p>
                  <div className="flex flex-col gap-3"><Button onClick={onReset} variant="danger" className="w-full py-3 justify-center text-lg">Yes, Delete Everything</Button><Button onClick={() => setShowResetConfirm(false)} variant="secondary" className="w-full py-3 justify-center">Cancel</Button></div>
              </div>
          </div>
      )}

      {showBabyModal && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 backdrop-blur-sm animate-fade-in">
              <div className="bg-white dark:bg-deep-card p-6 rounded-3xl shadow-2xl max-w-sm w-full border border-gray-200 dark:border-indigo-800">
                  <h3 className="text-xl font-bold mb-4 text-gray-800 dark:text-white">Enter Baby Details</h3>
                  <div className="space-y-4">
                      <div><label className="block text-sm font-bold mb-1 text-gray-700 dark:text-gray-300">Baby Name</label><input type="text" className="w-full px-4 py-2 border rounded-xl" value={babyForm.name} onChange={(e) => setBabyForm({...babyForm, name: e.target.value})} /></div>
                      <div><label className="block text-sm font-bold mb-1 text-gray-700 dark:text-gray-300">Birth Date</label><input type="date" className="w-full px-4 py-2 border rounded-xl" value={babyForm.date} max={new Date().toISOString().split('T')[0]} onChange={(e) => setBabyForm({...babyForm, date: e.target.value})} /></div>
                      <div>
                          <label className="block text-sm font-bold mb-1 text-gray-700 dark:text-gray-300">Gender</label>
                          <div className="flex gap-4">
                            <label className={`flex-1 flex items-center justify-center p-3 rounded-xl border cursor-pointer transition-all ${babyForm.gender === 'boy' ? 'border-blue-500 bg-blue-50 text-blue-600' : 'border-gray-200'}`}><input type="radio" name="gender" className="hidden" onClick={() => setBabyForm({...babyForm, gender: 'boy'})} />Boy</label>
                            <label className={`flex-1 flex items-center justify-center p-3 rounded-xl border cursor-pointer transition-all ${babyForm.gender === 'girl' ? 'border-pink-500 bg-pink-50 text-pink-600' : 'border-gray-200'}`}><input type="radio" name="gender" className="hidden" onClick={() => setBabyForm({...babyForm, gender: 'girl'})} />Girl</label>
                          </div>
                      </div>
                  </div>
                  <div className="flex gap-4 mt-6"><Button variant="secondary" onClick={() => setShowBabyModal(false)} className="flex-1">Cancel</Button><Button onClick={enablePostpartumMode} disabled={!babyForm.name || !babyForm.date} className="flex-1">Confirm</Button></div>
              </div>
          </div>
      )}
    </div>
  );
};

